export const RU_SPELLS: Spell[] = [...CURATED_SPELLS, ...parseSpells(SPELLS_COMPACT)]

// Index by lowercased name — used to turn «…» spell references into clickable links.
const SPELL_INDEX = new Map<string, Spell>()
for (const s of RU_SPELLS) {
  const k = s.name.trim().toLowerCase()
  if (!SPELL_INDEX.has(k)) SPELL_INDEX.set(k, s)
}

// Aliases — alternate names used in bestiary text (translation variants from
// next.dnd.su / fan translations) that map to a canonical curated entry.
const SPELL_ALIASES: Record<string, string> = {
  'чувства зверя': 'чутьё зверя',
  'электрошок': 'электрический захват',
  'шокирующий захват': 'электрический захват',
  'танцующие огоньки': 'пляшущие огоньки',
  'туманные шаги': 'туманный шаг',
  'бесшумное передвижение': 'тихое передвижение',
  'бесследное передвижение': 'тихое передвижение',
  'драконье общение': 'разговор с животными',
  'найти фамильяра': 'поиск фамильяра',
  'найти скакуна': 'поиск скакуна',
  'кара паладина': 'божественная кара'
}
for (const [alias, canonical] of Object.entries(SPELL_ALIASES)) {
  const s = SPELL_INDEX.get(canonical)
  if (s && !SPELL_INDEX.has(alias)) SPELL_INDEX.set(alias, s)
}

export function spellByName(name: string): Spell | undefined {
  return SPELL_INDEX.get(name.trim().toLowerCase())
}
